<template>
  <UserData @emit-submit="register" title="修改會員資料" :mode="mode" />
</template>

<script>
import { mapActions } from "pinia";
import { useLoadingStore } from "@/stores";
import { ErrorHelper, ConfirmAlert, TimerAlert, countdownCallbackTimerParam } from "@/helpers";
import { AuthService } from "@/services";
import { UserService } from "@/services/data/user";
import UserData from "@/components/auth/UserData.vue";

export default {
  data() {
    return {
      mode: AuthService.userDataMode.MODIFY_USER, // 使用者資料元件的運作模式
    };
  },

  methods: {
    /** loading 功能 */
    ...mapActions(useLoadingStore, {
      openLoading: "open",
      closeLoading: "close",
    }),

    /**
     * 註冊。
     * @param {Object} form 表單資料，由子元件傳入。
     */
    register(form) {
      console.log(`[register] form ====>`, form);

      this.openLoading();

      UserService.register(form)
        .then(() => {
          this.autoLogin(form.email, form.password);
        })
        .catch((error) => {
          console.error(`[register] 註冊失敗：`, error);
          ConfirmAlert.alertErrorDetail("註冊失敗", ErrorHelper.getErrorMsg(error));
        })
        .finally(() => {
          this.closeLoading();
        });
    },

    /**
     * 自動登入。
     * @param {string} account 帳號（使用 email）。
     * @param {string} password 密碼。
     */
    autoLogin(account, password) {
      const param = new countdownCallbackTimerParam();

      param.callback = () => {
        AuthService.loginAndRedirect(account, password);
      };

      param.title = "註冊成功！";
      param.desc = "將為您自動登入，若不想登入請點擊「離開」。";
      param.showConfirmButton = true;
      param.confirmButtonText = "立即登入";
      param.showDenyButton = true;
      param.denyButtonText = "離開";
      TimerAlert.alertCountdownCallback(param);
    },
  },

  components: { UserData },
};
</script>
